        Authorization: API_KEY,
      },
      body: JSON.stringify({
        model: MODEL,
        messages,
      }),
    });
    messages.push({
      role: "assistant",
      content: await response.json().content
    })
    document.body.innerHTML = JSON.stringify({ message: messages[messages.length - 1] } , "");
  } catch (error) {
    console.error(`Error: ${error}`);
